import { useState, useEffect } from 'react';
import { searchProduct } from '../services/openFoodFacts';

function IngredientCard({ item, onPackSelect, selectedPack }) {
  const packs = item.packs || [];

  return (
    <div className="ing-card">
      <div className="ing-card-top">
        <span className="ing-icon">{item.icon}</span>
        <div className="ing-info">
          <div className="ing-name">{item.realName || item.name}</div>
          <div className="ing-meta">
            {item.brand && item.brand + ' · '}
            Needed: {selectedPack?.qty || packs[0]?.qty}
          </div>
          <span className={item.fromOFF ? 'badge-green' : 'badge-yellow'}>
            {item.fromOFF ? 'Open Food Facts' : 'AI estimate'}
          </span>
        </div>
        <div className="ing-price">
          £{selectedPack ? selectedPack.price.toFixed(2) : packs[0]?.price.toFixed(2)}
        </div>
      </div>

      <div className="pack-options">
        {packs.map((pack, i) => (
          <button
            key={i}
            className={`pack-btn ${selectedPack?.label === pack.label ? 'pack-btn-selected' : ''}`}
            onClick={() => onPackSelect(item.name, pack)}
          >
            <span className="pack-label">{pack.label}</span>
            <span className="pack-price">£{pack.price.toFixed(2)}</span>
          </button>
        ))}
      </div>
    </div>
  );
}

function IngredientList({ ingredients, onAddToCart }) {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedPacks, setSelectedPacks] = useState({});

  useEffect(() => {
    const fetchAll = async () => {
      setLoading(true);
      const results = await Promise.all(
        ingredients.map(async (ing) => {
          let product = null;
          try {
            product = await searchProduct(ing.search);
          } catch (e) {
            console.log('OFF unavailable for:', ing.name);
          }
          return {
            ...ing,
            realName: product ? product.product_name || ing.name : ing.name,
            brand: product ? product.brands || '' : '',
            fromOFF: !!product,
          };
        })
      );

      const defaults = {};
      results.forEach(item => {
        if (item.packs && item.packs.length > 0) {
          defaults[item.name] = item.packs[0];
        }
      });

      setProducts(results);
      setSelectedPacks(defaults);
      setLoading(false);
    };
    fetchAll();
  }, [ingredients]);

  const handlePackSelect = (name, pack) => {
    setSelectedPacks(prev => ({ ...prev, [name]: pack }));
  };

  const handleAddToCart = () => {
    const cartItems = products.map(item => ({
      ...item,
      price: selectedPacks[item.name]?.price.toFixed(2) || '0.99',
      qty: selectedPacks[item.name]?.qty || item.packs?.[0]?.qty || '',
    }));
    onAddToCart(cartItems);
  };

  const total = products.reduce((sum, item) => {
    return sum + (selectedPacks[item.name]?.price || 0);
  }, 0);

  if (loading) return <div className="loading">Searching for real products...</div>;

  return (
    <div className="ingredient-list">
      <h2>Choose your packs</h2>
      <p>{products.filter(p => p.fromOFF).length} of {products.length} matched on Open Food Facts</p>
      {products.map((item, i) => (
        <IngredientCard
          key={i}
          item={item}
          selectedPack={selectedPacks[item.name]}
          onPackSelect={handlePackSelect}
        />
      ))}
      <div className="ing-total-row">
        <span>Estimated total</span>
        <strong>£{total.toFixed(2)}</strong>
      </div>
      <button className="main-btn" onClick={handleAddToCart}>
        Add all to cart →
      </button>
    </div>
  );
}

export default IngredientList;
